            aria-label={isFocusMode ? "Exit focus mode" : "Enter focus mode"}
            title={isFocusMode ? "Exit focus mode" : "Enter focus mode"}
          >
            {isFocusMode ? <FocusExitIcon /> : <FocusEnterIcon />}
