export const JournalEntry: React.FC<JournalEntryProps> = ({ entry, responses, onResponseChange, onShowToast, isFocusMode, onToggleFocusMode, imageUrl, onGenerateImage, isGeneratingImage, onShare, affirmation, isLoadingAffirmation, lyrics, isGeneratingLyrics, onGenerateLyrics, podcast, isGeneratingPodcast, onGeneratePodcast, lastChange, onUndo }) => {
