          const parsed = JSON.parse(storedImages);
          if (typeof parsed === 'object' && parsed !== null && !Array.isArray(parsed)) {
            return parsed;
          }
        }
        return {};
    } catch(e) {
        console.error("Failed to parse generated images from localStorage", e);
        return {};
    }
  });


